import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku } from '@sudoku/sudoku';
import { writable } from 'svelte/store';
// 导入新的 gamestore
import {
  userGrid,
  invalidCells,
  undo,
  redo,
  canUndo,
  canRedo,
  getShareableCode,
  isShareableCode,
  restoreFromShareCode,
  tryRestoreFromHash
} from '../../../stores/gamestore';

// ------------------------------
// 模拟老师的 grid store（初始固定棋盘）
// ------------------------------
let _initialGrid = Array(9).fill(null).map(() => Array(9).fill(0));

const { subscribe: initialGridSubscribe, set: initialGridSet } = writable(_initialGrid);

const grid = {
  subscribe: initialGridSubscribe,

  generate(difficulty) {
    const newGrid = generateSudoku(difficulty);
    _initialGrid = newGrid;
    initialGridSet(newGrid);
    // 注意：这里不再直接操作 game，因为 gamestore 会处理
  },

  decodeSencode(sencode) {
    const newGrid = decodeSencode(sencode);
    _initialGrid = newGrid;
    initialGridSet(newGrid);
    // 注意：这里不再直接操作 game，因为 gamestore 会处理
  },

  get(gridStore, x, y) {
    return gridStore[y][x];
  },

  getSencode(gridStore) {
    return encodeSudoku(gridStore);
  },
};

// ------------------------------
// 导出（保持与老师接口完全一致）
// ------------------------------
export { grid, userGrid, invalidCells, undo, redo, canUndo, canRedo };
export { getShareableCode, isShareableCode, restoreFromShareCode, tryRestoreFromHash };

